/* CSS-only tabs. Panels are absolutely stacked at their real 420px size and toggled with
   visibility (NOT display:none) so both terminals mount with correct dimensions — xterm
   mis-measures inside a 0-height container. */
.dsh-stack{display:flex;flex-direction:column;gap:12px}
.dsh-tin{display:none}
.dsh-tabs label.mud-tab{cursor:pointer;min-width:120px}
.dsh-tabs-paper{background:var(--mud-palette-surface);border:1px solid var(--mud-palette-lines-default);border-radius:0}
.dsh-panels{position:relative;height:420px}
.dsh-panel{position:absolute;top:0;left:0;right:0;bottom:0;visibility:hidden;overflow:hidden}
#dsh-t-logs:checked ~ .dsh-panels > .dsh-p-logs{visibility:visible}
#dsh-t-term:checked ~ .dsh-panels > .dsh-p-term{visibility:visible}
#dsh-t-details:checked ~ .dsh-panels > .dsh-p-details{visibility:visible}
#dsh-t-logs:checked ~ .mud-tabs-tabbar label[for="dsh-t-logs"],
#dsh-t-term:checked ~ .mud-tabs-tabbar label[for="dsh-t-term"],
#dsh-t-details:checked ~ .mud-tabs-tabbar label[for="dsh-t-details"]{color:var(--mud-palette-primary);box-shadow:inset 0 -2px 0 var(--mud-palette-primary)}

